// hooks/useLearn.js
// Custom React hook for calling POST /api/learn
// Handles: loading state, error state, response mapping
// Client-side cache: avoids re-fetching a topic already loaded this session

import { useState, useCallback, useRef } from "react";

const API_BASE = process.env.REACT_APP_API_URL || "http://localhost:5000";

export function useLearn() {
  const [loading, setLoading] = useState(false);
  const [error,   setError]   = useState(null);

  // Client-side session cache: { "percentages": { ...data } }
  const clientCache = useRef({});

  const fetchLearnContent = useCallback(async (topicName) => {
    if (!topicName) return null;

    const key = topicName.trim().toLowerCase();

    // Return from client cache immediately — no network call
    if (clientCache.current[key]) {
      return clientCache.current[key];
    }

    setLoading(true);
    setError(null);

    try {
      const res = await fetch(`${API_BASE}/api/learn`, {
        method:  "POST",
        headers: { "Content-Type": "application/json" },
        body:    JSON.stringify({ topic: topicName }),
      });

      // Parse JSON regardless of status so we can read the error message
      const json = await res.json();

      if (!res.ok || !json.success) {
        throw new Error(json.details || json.error || `Server error ${res.status}`);
      }

      // Store in client cache
      clientCache.current[key] = json.data;

      return json.data;

    } catch (err) {
      setError(err.message);
      return null;
    } finally {
      setLoading(false);
    }
  }, []);

  return { fetchLearnContent, loading, error };
}
